#include<bits/stdc++.h>
using namespace std;
int n,d;
int m;
string s,s1;
struct rule
{
    int i,hi,j,hj;
}p[100010];
vector<int> mp[100010];
int ch[100010][2],c[100010];
struct two_sat
{
    int low[100010],dfn[100010],dfncnt,scccnt,color[100010];
    bool instk[100010];
    stack<int> stk;
    void clear()
    {
        memset(low,0,sizeof(low));
        memset(dfn,0,sizeof(dfn));
        memset(color,0,sizeof(color));
        memset(instk,0,sizeof(instk));
        while(!stk.empty())
        {
            stk.pop();
        }
        dfncnt=scccnt=0;
    }
    void tarjan(int x)
    {
        low[x]=dfn[x]=++dfncnt;
        stk.push(x);
        instk[x]=1;
        for(int v:mp[x])
        {
            if(!dfn[v])
            {
                tarjan(v);
                low[x]=min(low[x],low[v]);
            }
            else if(instk[v])
            {
                low[x]=min(low[x],dfn[v]);
            }
        }
        if(low[x]==dfn[x])
        {
            scccnt++;
            int top;
            do
            {
                top=stk.top();
                stk.pop();
                color[top]=scccnt;
                instk[top]=0;
            }while(top!=x);
        }
    }
    void solve()
    {
        for(int i=1;i<=(n<<1);i++)
        {
            if(!dfn[i])
            {
                tarjan(i);
            }
        }
    }
    bool possible()
    {
        for(int i=1;i<=n;i++)
        {
            if(color[i]==color[i+n])
            {
                return false;
            }
        }
        return true;
    }
    bool getans(int x)
    {
        return color[x]<color[x+n];
    }
}t;
void zhuanhuan()
{
    for(int i=1;i<=n;i++)
    {
        c[i]=s[i-1]-'a'+1;
        int cnt=0;
        for(int j=1;j<=3;j++)if(j!=c[i])
        {
            ch[i][++cnt]=j;
        }
    }
}
void clear()
{
    for(int i=1;i<=n*2;i++)
    {
        mp[i].clear();
    }
    t.clear();
}
void check()
{
    clear();
    for(int r=1;r<=m;r++)
    {
        int i=p[r].i,j=p[r].j,hi=p[r].hi,hj=p[r].hj;
        if(c[i]==hi)
        {
            continue;
        }
        if(c[j]==hj)
        {
            if(hi==3||(hi==2&&c[i]==3))
            {
                mp[i+n].push_back(i);
            }
            else
            {
                mp[i].push_back(i+n);
            }
            continue;
        }
        int u1,v1,u2,v2;
        if(hi==3||(hi==2&&c[i]==3))
        {
            u1=i+n;
            u2=i;
        }
        else
        {
            u1=i;
            u2=i+n;
        }
        if(hj==3||(hj==2&&c[j]==3))
        {
            v1=j+n;
            v2=j;
        }
        else
        {
            v1=j;
            v2=j+n;
        }
        mp[u1].push_back(v1);
        mp[v2].push_back(u2);
    }
    t.solve();
    if(!t.possible())
    {
        return;
    }
    for(int i=0;i<n;i++)
    {
        if(t.getans(i+1))
        {
            s1[i]='A'-1+(c[i+1]==1?2:1);
        }
        else
        {
            s1[i]='A'-1+(c[i+1]==3?2:3);
        }
    }
    cout<<s1;
    exit(0);
}
int pos[100010],tot;
void dfs(int x)
{
    if(x==tot+1)
    {
        zhuanhuan();
        check();
        return;
    }
    s[pos[x]]='a';
    dfs(x+1);
    s[pos[x]]='b';
    dfs(x+1);
}
int main()
{
    scanf("%d%d",&n,&d);
    cin>>s;
    s1=s;
    for(int i=0;i<n;i++)
    {
        if(s[i]=='x')
        {
            pos[++tot]=i;
        }
    }
    scanf("%d",&m);
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&p[i].i);
        char ch;
        cin>>ch;
        p[i].hi=ch-'A'+1;
        scanf("%d",&p[i].j);
        cin>>ch;
        p[i].hj=ch-'A'+1;
    }
    dfs(1);
    printf("-1");
    return 0;
}
